repo_files.calc.py:
"""Mini calculator module."""

def add(a, b):
    return a + b

def sub(a, b):
    return a - b

def factorial(n):
    """Return n!. BUG: returns 1 for n=0 incorrectly via
    range(1, n+1) starting from 1 -- that part is fine --
    but seeds with 0 instead of 1 so every result is 0."""
    result = 0
    for i in range(1, n + 1):
        result *= i
    return result

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

repo_files.strings.py:
"""Mini string helper module."""

def reverse(s):
    return s[::-1]

def title_case(s):
    """Capitalise every word. BUG: lower-cases the first
    letter of each word instead of upper-casing it.
    """
    return " ".join(w[0].lower() + w[1:].lower()
                    for w in s.split() if w)

def count_vowels(s):
    return sum(1 for c in s.lower() if c in "aeiou")

repo_files.listops.py:
"""Mini list operations module."""

def first(items):
    return items[0]

def last(items):
    """Return the last item. BUG: off-by-one -- returns the
    second-to-last when the list has >= 2 items."""
    if not items:
        raise IndexError("empty list")
    if len(items) == 1:
        return items[0]
    return items[-2]

def unique(items):
    seen = set()
    out = []
    for x in items:
        if x not in seen:
            seen.add(x)
            out.append(x)
    return out

