repo_files.dictops.py:
"""Mini dict helpers."""

def merge(a, b):
    """Return a new dict with a's keys overridden by b's.
    BUG: returns ``a`` directly mutated instead of a copy.
    """
    a.update(b)
    return a

def keys_sorted(d):
    return sorted(d.keys())

def value_count(d, value):
    return sum(1 for v in d.values() if v == value)

repo_files.text.py:
"""Mini text helpers."""

def word_count(s):
    """Count words. BUG: subtracts 1 unnecessarily."""
    return len(s.split()) - 1

def strip_punct(s):
    return ''.join(c for c in s if c.isalnum() or c.isspace())

repo_files.stats.py:
"""Mini stats helpers."""

def average(xs):
    """BUG: returns median instead of mean."""
    return sorted(xs)[len(xs) // 2]

def variance(xs):
    m = sum(xs) / len(xs)
    return sum((x - m) ** 2 for x in xs) / len(xs)
